  # Render a Lucide icon as inline SVG (currentColor, 24×24 viewBox).
  def icon(name, size: 24, stroke: 2, css: nil)
    paths = ICON_PATHS[name.to_s] || ""
    size = size.to_i
    klass = css ? %( class="#{ERB::Util.html_escape(css)}") : ""
    <<~SVG.html_safe
      <svg xmlns="http://www.w3.org/2000/svg" width="#{size}" height="#{size}" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="#{stroke}" stroke-linecap="round" stroke-linejoin="round"#{klass} aria-hidden="true">#{paths}</svg>
    SVG
  end

  # A tinted soft-color background (10% of a hex) for an icon badge.
  def soft_bg(hex)
    "#{hex}16"
  end

  # Format an amount of cents as BRL, dropping ",00" for whole values.
  # 9_900 → "R$ 99" · 129_900 → "R$ 1.299" · 9_990 → "R$ 99,90"
  def brl_short(cents)
    reais  = cents / 100
    rest   = cents % 100
    grouped = reais.to_s.reverse.gsub(/(\d{3})(?=\d)/, '\\1.').reverse
    rest.zero? ? "R$ #{grouped}" : format("R$ %s,%02d", grouped, rest)
  end

  # Human seat label derived from the canonical plan seat count.
  def plan_seats_label(seats)
    return "1 assento" if seats <= 1
    return "Assentos ilimitados" if seats >= 9_999

    "Até #{seats} assentos"
  end

  # Is the given path prefix the active section (for nav highlighting)?
  def nav_section_active?(prefix)
    request.path == prefix || request.path.start_with?("#{prefix}/")
  end
end
